def missing_summary(df, sort=True):
    summary = pd.DataFrame({
        'missing_count': df.isna().sum(),
        'missing_percent': round(df.isna().mean() * 100, 2)})

    if sort:
        summary = summary.sort_values(by='missing_count', ascending=False)

    return summary

